INSERT INTO public.instructors (id, name, headline, avatar_url, bio, rating, student_count, course_count) VALUES
  ('ins-1', 'Amara Okafor', 'Senior Frontend Engineer, ex-Stripe', 'amara', 'Amara has spent a decade building production interfaces at scale and has taught over 90,000 students how modern web apps actually get built.', 4.8, 94210, 6),
  ('ins-2', 'Daniel Kessler', 'Brand & Product Designer', 'daniel', 'Daniel leads design at a fintech startup and previously worked at two design agencies in Berlin. He teaches design systems thinking from first principles.', 4.9, 51230, 4),
  ('ins-3', 'Priya Raman', 'Independent Tutor · Data & AI', 'priya', 'Priya is a self-taught data scientist who left consulting to teach full time. Her courses focus on practical, portfolio-ready projects.', 4.7, 28890, 5),
  ('ins-4', 'Marcus Webb', 'Growth Marketer & Founder', 'marcus', 'Marcus has run growth for three venture-backed startups and now teaches the channels and frameworks that actually move revenue.', 4.6, 33410, 3),
  ('ins-5', 'Sofia Lindqvist', 'Independent Tutor · Visual Arts', 'sofia', 'Sofia is a working photographer and colorist who teaches the technical craft behind editorial and travel photography.', 4.9, 19040, 4),
  ('ins-6', 'Tomasz Nowak', 'Backend Architect, 12+ yrs', 'tomasz', 'Tomasz has designed backend systems for companies processing millions of requests a day, and teaches systems design with real production stories.', 4.8, 67550, 5),
  ('ins-7', 'Naledi Dube', 'Executive Coach & Author', 'naledi', 'Naledi coaches founders and executives on focus, communication and decision-making, distilled from 15 years of 1:1 coaching practice.', 4.9, 22170, 3),
  ('ins-8', 'Leo Fontaine', 'Independent Tutor · Music Production', 'leo', 'Leo produces for independent artists and teaches music production from a home-studio budget upward.', 4.7, 15680, 3)
INSERT INTO public.courses (id, slug, title, subtitle, description, thumbnail_url, provider, instructor_id, category_id, level, price, original_price, rating, rating_count, student_count, duration_hours, lecture_count, bestseller, is_new, tags, what_you_will_learn, requirements, curriculum) VALUES
  ('c-1', 'modern-javascript-frameworks', 'Modern JavaScript: From Fundamentals to Frameworks', 'Master JS, then build real apps with React and TypeScript', 'A project-driven path through modern JavaScript: closures, async patterns, the module system, and the mental models you need before picking up React and TypeScript. Ends with three deployable projects for your portfolio.', 'dev-1', 'Curio Original', 'ins-1', 'cat-dev', 'Beginner', 49.99, 129.99, 4.8, 12480, 58210, 32, 186, true, false, '{JavaScript,React,TypeScript}', '{Write idiomatic modern JavaScript without relying on guesswork,Reason about async code: promises, async/await, and event loops,Build component-based UIs with React,Add type safety to a real app using TypeScript,Ship three portfolio-ready projects}', '{Basic HTML & CSS,A computer with Node.js installed,No prior JS experience required}', '{{"id":"sec-0","title":"JavaScript Foundations","lessons":[{"id":"les-0-0","title":"JavaScript Foundations — Part 1","duration_minutes":6,"is_preview":true},{"id":"les-0-1","title":"JavaScript Foundations — Part 2","duration_minutes":9,"is_preview":false},{"id":"les-0-2","title":"JavaScript Foundations — Part 3","duration_minutes":12,"is_preview":false}]},{"id":"sec-1","title":"Asynchronous Patterns","lessons":[{"id":"les-1-0","title":"Asynchronous Patterns — Part 1","duration_minutes":9,"is_preview":false},{"id":"les-1-1","title":"Asynchronous Patterns — Part 2","duration_minutes":12,"is_preview":false},{"id":"les-1-2","title":"Asynchronous Patterns — Part 3","duration_minutes":15,"is_preview":false}]},{"id":"sec-2","title":"The Module System & Tooling","lessons":[{"id":"les-2-0","title":"The Module System & Tooling — Part 1","duration_minutes":12,"is_preview":false},{"id":"les-2-1","title":"The Module System & Tooling — Part 2","duration_minutes":15,"is_preview":false},{"id":"les-2-2","title":"The Module System & Tooling — Part 3","duration_minutes":18,"is_preview":false}]},{"id":"sec-3","title":"React Fundamentals","lessons":[{"id":"les-3-0","title":"React Fundamentals — Part 1","duration_minutes":15,"is_preview":false},{"id":"les-3-1","title":"React Fundamentals — Part 2","duration_minutes":18,"is_preview":false}]},{"id":"sec-4","title":"Typing Your App with TypeScript","lessons":[{"id":"les-4-0","title":"Typing Your App with TypeScript — Part 1","duration_minutes":18,"is_preview":false},{"id":"les-4-1","title":"Typing Your App with TypeScript — Part 2","duration_minutes":21,"is_preview":false},{"id":"les-4-2","title":"Typing Your App with TypeScript — Part 3","duration_minutes":24,"is_preview":false}]},{"id":"sec-5","title":"Capstone Projects","lessons":[{"id":"les-5-0","title":"Capstone Projects — Part 1","duration_minutes":21,"is_preview":false}]}}'),
  ('c-2', 'backend-systems-design', 'Backend Systems Design: Building for Scale', 'APIs, queues, caching and databases that hold up under load', 'Move beyond CRUD. Learn how production backends actually handle scale: caching layers, message queues, database indexing strategy, and the tradeoffs senior engineers weigh every day, told through real incident stories.', 'dev-2', 'Udemy', 'ins-6', 'cat-dev', 'Advanced', 64.99, 159.99, 4.9, 8120, 31900, 28, 142, true, false, '{System Design,Databases,APIs}', '{Design APIs that scale gracefully under real traffic,Choose the right caching layer for a given problem,Use message queues to decouple services,Index and shard databases without guessing}', '{Comfortable with at least one backend language,Basic SQL knowledge}', '{{"id":"sec-0","title":"API Design Principles","lessons":[{"id":"les-0-0","title":"API Design Principles — Part 1","duration_minutes":6,"is_preview":true},{"id":"les-0-1","title":"API Design Principles — Part 2","duration_minutes":9,"is_preview":false},{"id":"les-0-2","title":"API Design Principles — Part 3","duration_minutes":12,"is_preview":false}]},{"id":"sec-1","title":"Caching Strategies","lessons":[{"id":"les-1-0","title":"Caching Strategies — Part 1","duration_minutes":9,"is_preview":false},{"id":"les-1-1","title":"Caching Strategies — Part 2","duration_minutes":12,"is_preview":false},{"id":"les-1-2","title":"Caching Strategies — Part 3","duration_minutes":15,"is_preview":false}]},{"id":"sec-2","title":"Message Queues & Eventing","lessons":[{"id":"les-2-0","title":"Message Queues & Eventing — Part 1","duration_minutes":12,"is_preview":false},{"id":"les-2-1","title":"Message Queues & Eventing — Part 2","duration_minutes":15,"is_preview":false},{"id":"les-2-2","title":"Message Queues & Eventing — Part 3","duration_minutes":18,"is_preview":false}]},{"id":"sec-3","title":"Database Indexing & Sharding","lessons":[{"id":"les-3-0","title":"Database Indexing & Sharding — Part 1","duration_minutes":15,"is_preview":false},{"id":"les-3-1","title":"Database Indexing & Sharding — Part 2","duration_minutes":18,"is_preview":false}]},{"id":"sec-4","title":"Observability & Incident Response","lessons":[{"id":"les-4-0","title":"Observability & Incident Response — Part 1","duration_minutes":18,"is_preview":false},{"id":"les-4-1","title":"Observability & Incident Response — Part 2","duration_minutes":21,"is_preview":false},{"id":"les-4-2","title":"Observability & Incident Response — Part 3","duration_minutes":24,"is_preview":false}]}}'),
  ('c-3', 'uiux-design-foundations', 'UI/UX Design Foundations: From Wireframe to Prototype', 'A complete, portfolio-first path into product design', 'Learn the full design process — research, wireframing, visual systems, and interactive prototyping — by designing a real product end to end. Built for people switching careers into product design.', 'design-1', 'Curio Original', 'ins-2', 'cat-design', 'Beginner', 44.99, 99.99, 4.9, 9870, 41200, 24, 118, true, false, '{UX Research,Figma,Design Systems}', '{Run lightweight user research that actually informs decisions,Structure information so products feel obvious to use,Build a cohesive visual design system,Prototype interactions that feel real, not flat}', '{No design experience needed,Figma (free plan is fine)}', '{{"id":"sec-0","title":"Design Process & Research","lessons":[{"id":"les-0-0","title":"Design Process & Research — Part 1","duration_minutes":6,"is_preview":true},{"id":"les-0-1","title":"Design Process & Research — Part 2","duration_minutes":9,"is_preview":false},{"id":"les-0-2","title":"Design Process & Research — Part 3","duration_minutes":12,"is_preview":false}]},{"id":"sec-1","title":"Wireframing & Information Architecture","lessons":[{"id":"les-1-0","title":"Wireframing & Information Architecture — Part 1","duration_minutes":9,"is_preview":false},{"id":"les-1-1","title":"Wireframing & Information Architecture — Part 2","duration_minutes":12,"is_preview":false},{"id":"les-1-2","title":"Wireframing & Information Architecture — Part 3","duration_minutes":15,"is_preview":false}]},{"id":"sec-2","title":"Visual Design Systems","lessons":[{"id":"les-2-0","title":"Visual Design Systems — Part 1","duration_minutes":12,"is_preview":false},{"id":"les-2-1","title":"Visual Design Systems — Part 2","duration_minutes":15,"is_preview":false},{"id":"les-2-2","title":"Visual Design Systems — Part 3","duration_minutes":18,"is_preview":false}]},{"id":"sec-3","title":"Prototyping & Micro-interactions","lessons":[{"id":"les-3-0","title":"Prototyping & Micro-interactions — Part 1","duration_minutes":15,"is_preview":false},{"id":"les-3-1","title":"Prototyping & Micro-interactions — Part 2","duration_minutes":18,"is_preview":false}]},{"id":"sec-4","title":"Building Your Portfolio Case Study","lessons":[{"id":"les-4-0","title":"Building Your Portfolio Case Study — Part 1","duration_minutes":18,"is_preview":false},{"id":"les-4-1","title":"Building Your Portfolio Case Study — Part 2","duration_minutes":21,"is_preview":false},{"id":"les-4-2","title":"Building Your Portfolio Case Study — Part 3","duration_minutes":24,"is_preview":false}]}}'),
  ('c-4', 'brand-identity-design', 'Brand Identity Design: Logos, Systems & Guidelines', 'Design cohesive brand identities clients actually approve', 'A studio-style walkthrough of the brand identity process: discovery, logo exploration, color and type systems, and packaging it all into a guideline document clients can hand to any vendor.', 'design-2', 'Independent Tutor', 'ins-2', 'cat-design', 'Intermediate', 39.99, NULL, 4.7, 3210, 14880, 16, 74, false, true, '{Branding,Logo Design,Style Guides}', '{Run a brand discovery session with a client,Explore and narrow logo concepts methodically,Build a complete color and type system,Package an identity into a professional guideline}', '{Basic familiarity with a design tool (Figma, Illustrator, or similar)}', '{{"id":"sec-0","title":"Brand Discovery & Strategy","lessons":[{"id":"les-0-0","title":"Brand Discovery & Strategy — Part 1","duration_minutes":6,"is_preview":true},{"id":"les-0-1","title":"Brand Discovery & Strategy — Part 2","duration_minutes":9,"is_preview":false},{"id":"les-0-2","title":"Brand Discovery & Strategy — Part 3","duration_minutes":12,"is_preview":false}]},{"id":"sec-1","title":"Logo Exploration & Mark-Making","lessons":[{"id":"les-1-0","title":"Logo Exploration & Mark-Making — Part 1","duration_minutes":9,"is_preview":false},{"id":"les-1-1","title":"Logo Exploration & Mark-Making — Part 2","duration_minutes":12,"is_preview":false},{"id":"les-1-2","title":"Logo Exploration & Mark-Making — Part 3","duration_minutes":15,"is_preview":false}]},{"id":"sec-2","title":"Color & Typography Systems","lessons":[{"id":"les-2-0","title":"Color & Typography Systems — Part 1","duration_minutes":12,"is_preview":false},{"id":"les-2-1","title":"Color & Typography Systems — Part 2","duration_minutes":15,"is_preview":false},{"id":"les-2-2","title":"Color & Typography Systems — Part 3","duration_minutes":18,"is_preview":false}]},{"id":"sec-3","title":"Assembling the Brand Guideline","lessons":[{"id":"les-3-0","title":"Assembling the Brand Guideline — Part 1","duration_minutes":15,"is_preview":false},{"id":"les-3-1","title":"Assembling the Brand Guideline — Part 2","duration_minutes":18,"is_preview":false}]}}'),
  ('c-5', 'python-data-science-bootcamp', 'Python for Data Science: The Practical Bootcamp', 'Pandas, visualization and real-world analysis projects', 'Skip the theory-heavy intros. This bootcamp gets you cleaning, analyzing and visualizing real datasets in your first week, building toward a complete analysis project you can show employers.', 'data-1', 'Independent Tutor', 'ins-3', 'cat-data', 'Beginner', 54.99, 119.99, 4.7, 15600, 72340, 30, 160, true, false, '{Python,Pandas,Data Visualization}', '{Clean and reshape messy real-world data,Explore datasets to find the story inside them,Build clear, honest visualizations,Present an end-to-end analysis project}', '{No prior Python experience required}', '{{"id":"sec-0","title":"Python Refresher for Data Work","lessons":[{"id":"les-0-0","title":"Python Refresher for Data Work — Part 1","duration_minutes":6,"is_preview":true},{"id":"les-0-1","title":"Python Refresher for Data Work — Part 2","duration_minutes":9,"is_preview":false},{"id":"les-0-2","title":"Python Refresher for Data Work — Part 3","duration_minutes":12,"is_preview":false}]},{"id":"sec-1","title":"Data Cleaning with Pandas","lessons":[{"id":"les-1-0","title":"Data Cleaning with Pandas — Part 1","duration_minutes":9,"is_preview":false},{"id":"les-1-1","title":"Data Cleaning with Pandas — Part 2","duration_minutes":12,"is_preview":false},{"id":"les-1-2","title":"Data Cleaning with Pandas — Part 3","duration_minutes":15,"is_preview":false}]},{"id":"sec-2","title":"Exploratory Data Analysis","lessons":[{"id":"les-2-0","title":"Exploratory Data Analysis — Part 1","duration_minutes":12,"is_preview":false},{"id":"les-2-1","title":"Exploratory Data Analysis — Part 2","duration_minutes":15,"is_preview":false},{"id":"les-2-2","title":"Exploratory Data Analysis — Part 3","duration_minutes":18,"is_preview":false}]},{"id":"sec-3","title":"Visualization with Matplotlib & Seaborn","lessons":[{"id":"les-3-0","title":"Visualization with Matplotlib & Seaborn — Part 1","duration_minutes":15,"is_preview":false},{"id":"les-3-1","title":"Visualization with Matplotlib & Seaborn — Part 2","duration_minutes":18,"is_preview":false}]},{"id":"sec-4","title":"Capstone: End-to-End Analysis","lessons":[{"id":"les-4-0","title":"Capstone: End-to-End Analysis — Part 1","duration_minutes":18,"is_preview":false},{"id":"les-4-1","title":"Capstone: End-to-End Analysis — Part 2","duration_minutes":21,"is_preview":false},{"id":"les-4-2","title":"Capstone: End-to-End Analysis — Part 3","duration_minutes":24,"is_preview":false}]}}'),
  ('c-6', 'machine-learning-foundations', 'Machine Learning Foundations: Models That Actually Work', 'From linear regression to gradient boosting, with intuition first', 'A model-by-model tour of machine learning built around intuition before math. Each model is taught through a real dataset, with an honest look at when it works, when it fails, and why.', 'data-2', 'Coursera Partner', 'ins-3', 'cat-data', 'Intermediate', 69.99, 149.99, 4.8, 6790, 25430, 38, 174, false, false, '{Machine Learning,scikit-learn,Statistics}', '{Build intuition for how core ML models actually work,Choose the right model for a given dataset,Evaluate models without fooling yourself,Avoid the most common beginner mistakes in ML projects}', '{Comfortable with Python,High-school level algebra}', '{{"id":"sec-0","title":"Intuition Before Math","lessons":[{"id":"les-0-0","title":"Intuition Before Math — Part 1","duration_minutes":6,"is_preview":true},{"id":"les-0-1","title":"Intuition Before Math — Part 2","duration_minutes":9,"is_preview":false},{"id":"les-0-2","title":"Intuition Before Math — Part 3","duration_minutes":12,"is_preview":false}]},{"id":"sec-1","title":"Regression Models","lessons":[{"id":"les-1-0","title":"Regression Models — Part 1","duration_minutes":9,"is_preview":false},{"id":"les-1-1","title":"Regression Models — Part 2","duration_minutes":12,"is_preview":false},{"id":"les-1-2","title":"Regression Models — Part 3","duration_minutes":15,"is_preview":false}]},{"id":"sec-2","title":"Classification Models","lessons":[{"id":"les-2-0","title":"Classification Models — Part 1","duration_minutes":12,"is_preview":false},{"id":"les-2-1","title":"Classification Models — Part 2","duration_minutes":15,"is_preview":false},{"id":"les-2-2","title":"Classification Models — Part 3","duration_minutes":18,"is_preview":false}]},{"id":"sec-3","title":"Tree-Based Methods & Boosting","lessons":[{"id":"les-3-0","title":"Tree-Based Methods & Boosting — Part 1","duration_minutes":15,"is_preview":false},{"id":"les-3-1","title":"Tree-Based Methods & Boosting — Part 2","duration_minutes":18,"is_preview":false}]},{"id":"sec-4","title":"Model Evaluation You Can Trust","lessons":[{"id":"les-4-0","title":"Model Evaluation You Can Trust — Part 1","duration_minutes":18,"is_preview":false},{"id":"les-4-1","title":"Model Evaluation You Can Trust — Part 2","duration_minutes":21,"is_preview":false},{"id":"les-4-2","title":"Model Evaluation You Can Trust — Part 3","duration_minutes":24,"is_preview":false}]}}'),
  ('c-7', 'growth-marketing-playbook', 'The Growth Marketing Playbook', 'Channels, experiments and funnels that compound', 'A no-fluff walkthrough of how startups actually grow: choosing channels, running experiments that produce real signal, and building funnels that compound instead of leaking.', 'marketing-1', 'Curio Original', 'ins-4', 'cat-marketing', 'Intermediate', 49.99, NULL, 4.6, 4310, 19870, 18, 92, false, false, '{Growth,Funnels,A/B Testing}', '{Pick growth channels based on evidence, not trends,Design experiments that actually produce a signal,Build a funnel that compounds over time,Diagnose where a funnel is leaking}', '{Some familiarity with a startup or small business context is helpful}', '{{"id":"sec-0","title":"Choosing Your First Channels","lessons":[{"id":"les-0-0","title":"Choosing Your First Channels — Part 1","duration_minutes":6,"is_preview":true},{"id":"les-0-1","title":"Choosing Your First Channels — Part 2","duration_minutes":9,"is_preview":false},{"id":"les-0-2","title":"Choosing Your First Channels — Part 3","duration_minutes":12,"is_preview":false}]},{"id":"sec-1","title":"Designing Real Experiments","lessons":[{"id":"les-1-0","title":"Designing Real Experiments — Part 1","duration_minutes":9,"is_preview":false},{"id":"les-1-1","title":"Designing Real Experiments — Part 2","duration_minutes":12,"is_preview":false},{"id":"les-1-2","title":"Designing Real Experiments — Part 3","duration_minutes":15,"is_preview":false}]},{"id":"sec-2","title":"Funnel Architecture","lessons":[{"id":"les-2-0","title":"Funnel Architecture — Part 1","duration_minutes":12,"is_preview":false},{"id":"les-2-1","title":"Funnel Architecture — Part 2","duration_minutes":15,"is_preview":false},{"id":"les-2-2","title":"Funnel Architecture — Part 3","duration_minutes":18,"is_preview":false}]},{"id":"sec-3","title":"Retention & Compounding Growth","lessons":[{"id":"les-3-0","title":"Retention & Compounding Growth — Part 1","duration_minutes":15,"is_preview":false},{"id":"les-3-1","title":"Retention & Compounding Growth — Part 2","duration_minutes":18,"is_preview":false}]}}'),
  ('c-8', 'seo-content-strategy', 'SEO & Content Strategy That Actually Ranks', 'Research, structure and write content built to be found', 'Learn the research and structural work behind content that ranks: keyword clustering, search intent, on-page structure, and a sustainable content calendar that doesn''t burn you out.', 'marketing-2', 'Independent Tutor', 'ins-4', 'cat-marketing', 'Beginner', 34.99, 79.99, 4.5, 2980, 13210, 12, 58, false, false, '{SEO,Content Writing,Keyword Research}', '{Cluster keywords around real search intent,Structure pages that both readers and search engines understand,Plan a content calendar you can sustain}', '{A website or blog you''re actively writing for is helpful but not required}', '{{"id":"sec-0","title":"Understanding Search Intent","lessons":[{"id":"les-0-0","title":"Understanding Search Intent — Part 1","duration_minutes":6,"is_preview":true},{"id":"les-0-1","title":"Understanding Search Intent — Part 2","duration_minutes":9,"is_preview":false},{"id":"les-0-2","title":"Understanding Search Intent — Part 3","duration_minutes":12,"is_preview":false}]},{"id":"sec-1","title":"Keyword Research & Clustering","lessons":[{"id":"les-1-0","title":"Keyword Research & Clustering — Part 1","duration_minutes":9,"is_preview":false},{"id":"les-1-1","title":"Keyword Research & Clustering — Part 2","duration_minutes":12,"is_preview":false},{"id":"les-1-2","title":"Keyword Research & Clustering — Part 3","duration_minutes":15,"is_preview":false}]},{"id":"sec-2","title":"On-Page Structure That Ranks","lessons":[{"id":"les-2-0","title":"On-Page Structure That Ranks — Part 1","duration_minutes":12,"is_preview":false},{"id":"les-2-1","title":"On-Page Structure That Ranks — Part 2","duration_minutes":15,"is_preview":false},{"id":"les-2-2","title":"On-Page Structure That Ranks — Part 3","duration_minutes":18,"is_preview":false}]},{"id":"sec-3","title":"Building a Sustainable Content Calendar","lessons":[{"id":"les-3-0","title":"Building a Sustainable 