  ('c-9', 'startup-finance-fundamentals', 'Startup Finance Fundamentals', 'Model your runway, raise smart, and read a cap table', 'Everything a non-finance founder needs: building a simple financial model, understanding runway and burn, reading a cap table, and knowing what investors are actually evaluating.', 'business-1', 'Curio Original', 'ins-7', 'cat-business', 'Beginner', 59.99, NULL, 4.8, 3650, 16700, 14, 64, false, true, '{Finance,Fundraising,Startups}', '{Build a simple, honest financial model,Track runway and burn without a finance background,Read and understand a cap table,Prepare for early investor conversations}', '{No finance background required}', '{{"id":"sec-0","title":"Building Your First Financial Model","lessons":[{"id":"les-0-0","title":"Building Your First Financial Model — Part 1","duration_minutes":6,"is_preview":true},{"id":"les-0-1","title":"Building Your First Financial Model — Part 2","duration_minutes":9,"is_preview":false},{"id":"les-0-2","title":"Building Your First Financial Model — Part 3","duration_minutes":12,"is_preview":false}]},{"id":"sec-1","title":"Runway & Burn Rate","lessons":[{"id":"les-1-0","title":"Runway & Burn Rate — Part 1","duration_minutes":9,"is_preview":false},{"id":"les-1-1","title":"Runway & Burn Rate — Part 2","duration_minutes":12,"is_preview":false},{"id":"les-1-2","title":"Runway & Burn Rate — Part 3","duration_minutes":15,"is_preview":false}]},{"id":"sec-2","title":"Reading a Cap Table","lessons":[{"id":"les-2-0","title":"Reading a Cap Table — Part 1","duration_minutes":12,"is_preview":false},{"id":"les-2-1","title":"Reading a Cap Table — Part 2","duration_minutes":15,"is_preview":false},{"id":"les-2-2","title":"Reading a Cap Table — Part 3","duration_minutes":18,"is_preview":false}]},{"id":"sec-3","title":"What Investors Actually Look At","lessons":[{"id":"les-3-0","title":"What Investors Actually Look At — Part 1","duration_minutes":15,"is_preview":false},{"id":"les-3-1","title":"What Investors Actually Lo